    // Function to calculate the popcount of a number
    function popcount(x) {
        return x.toString(2).split('1').length - 1;
    }

    // Function to calculate the popcount-depth of a number
    function popcountDepth(x, k) {
        let depth = 0;
        while (x !== 1) {
            x = popcount(x);
            depth++;
            if (depth > k) return -1; // If depth exceeds k, return -1
        }
        return depth;
    }

    // Count numbers in [1, n] with popcount-depth exactly equal to k
    let count = 0;
    for (let i = 1; i <= n; i++) {
        if (popcountDepth(i, k) === k) {
            count++;
        }
    }
    return count;
}

